import json
import requests
import logging

# Configure logging
logger = logging.getLogger()
logger.setLevel(logging.INFO)

def lambda_handler(event, context):
    """
    Lambda@Edge function to enrich viewer requests by fetching data from URLs
    specified in the 'X-Enrich-URL' header.
    """
    request = event['Records'][0]['cf']['request']
    headers = request['headers']

    # CloudFront normalizes header names to lowercase
    enrich_urls_header = headers.get('x-enrich-url')

    if enrich_urls_header:
        # The header value is a list of dicts, e.g., [{'key': 'X-Enrich-URL', 'value': 'url1,url2'}]
        # We expect a single value for this header, which might contain comma-separated URLs.
        enrich_urls_str = enrich_urls_header[0]['value']
        enrich_urls = [url.strip() for url in enrich_urls_str.split(',') if url.strip()]

        enriched_data_list = []

        for url in enrich_urls:
            try:
                logger.info(f"Attempting to fetch enrichment data from: {url}")
                # Use a timeout to prevent long-running requests that might exceed Lambda limits
                response = requests.get(url, timeout=2) # 2 seconds timeout for each request
                response.raise_for_status() # Raise an exception for HTTP errors (4xx or 5xx)

                # Assuming the enrichment data is JSON
                enrichment_data = response.json()
                enriched_data_list.append(enrichment_data)
                logger.info(f"Successfully fetched data from {url}")

            except requests.exceptions.Timeout:
                logger.error(f"Timeout occurred while fetching data from {url}")
            except requests.exceptions.RequestException as e:
                logger.error(f"HTTP request error fetching data from {url}: {e}")
            except json.JSONDecodeError:
                logger.error(f"Failed to decode JSON from {url}. Response text (first 200 chars): {response.text[:200]}...")
            except Exception as e:
                logger.error(f"An unexpected error occurred for URL {url}: {e}")

        if enriched_data_list:
            # Combine all fetched data into a single JSON string.
            # In a production scenario, you might have more complex merging logic
            # or choose to add specific fields as separate headers.
            combined_enriched_data_json = json.dumps(enriched_data_list)

            # Add the enriched data as a new header to the request.
            # CloudFront header values must be strings.
            # Ensure the header name is also added to the request.
            headers['x-enriched-context'] = [{
                'key': 'X-Enriched-Context',
                'value': combined_enriched_data_json
            }]
            logger.info("Added 'X-Enriched-Context' header to the request.")
        else:
            logger.info("No enrichment data was successfully fetched from any specified URL.")
    else:
        logger.info("No 'X-Enrich-URL' header found in the request. No enrichment performed.")

    return request